INSERT INTO `notification_templates` VALUES (1,'ALERT_CRITICAL','EMAIL','🔴 CRITICAL · {{alert_code}} · {{disease_name}} at {{poe_code}}','<!doctype html><html><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"><title>Critical alert raised at {{poe_code}}</title></head><body style=\"margin:0;background:#F8FAFC;font-family:-apple-system,BlinkMacSystemFont,\'Segoe UI\',Roboto,sans-serif;color:#0F172A;line-height:1.45;\"><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background:#F8FAFC;padding:24px 12px;\"><tr><td align=\"center\"><table role=\"presentation\" width=\"640\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"max-width:640px;width:100%;background:#FFFFFF;border-radius:12px;overflow:hidden;box-shadow:0 1px 3px rgba(15,23,42,0.08);\"><tr><td style=\"padding:16px 24px;background:#B91C1C;color:#FFFFFF;font-weight:600;font-size:13px;letter-spacing:.08em;text-transform:uppercase;\">🇺🇬 UGANDA POE SENTINEL · CRITICAL ALERT</td></tr><tr><td style=\"padding:24px 24px 6px 24px;\"><div style=\"font-size:11px;color:#64748B;letter-spacing:.06em;text-transform:uppercase;font-weight:600;\">{{now}} · Africa/Kampala</div><h1 style=\"margin:8px 0 6px 0;font-size:20px;line-height:1.3;color:#0F172A;font-weight:700;\">Critical alert raised at {{poe_code}}</h1><p style=\"margin:0;color:#475569;font-size:13.5px;\">A traveller meeting case-definition for {{disease_name}} has been flagged for the highest response tier.</p></td></tr><tr><td style=\"padding:14px 24px 20px 24px;\"><div style=\"margin-bottom:14px;\"><span style=\"display:inline-block;padding:3px 10px;background:#FEF2F2;color:#B91C1C;border-radius:999px;font-size:11px;font-weight:700;letter-spacing:.04em;text-transform:uppercase;\">{{risk_level_label}}</span></div><table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin:6px 0 14px 0;border-collapse:collapse;\"><