INSERT INTO `ref_diseases` VALUES (1,'smallpox','Smallpox',1,'vesiculopustular_rash',7,17,'{\"cfr_pct\": 30, \"severity\": 5, \"hallmarks\": [\"fever\", \"rash_vesicular_pustular\", \"rash_face_first\"], \"syndromes\": [\"vesiculopustular_rash\", \"high_consequence_rash\"], \"who_basis\": \"IHR 2005 — always notifiable. WHO smallpox eradication surveillance guidance.\", \"who_category\": \"IHR_TIER1_ALWAYS_NOTIFIABLE\", \"priority_tier\": \"tier_1_ihr_critical\", \"immediate_actions\": [\"MAXIMUM ISOLATION\", \"IMMEDIATE IHR WHO NOTIFICATION\", \"BIOTERRORISM PROTOCOL\", \"Contact tracing of all contacts since rash onset\"], \"recommended_tests\": [\"Immediate WHO/national public health emergency pathway — BSL-4 only\", \"DO NOT attempt routine lab — activate bioterrorism protocol\"], \"key_distinguishers\": [\"Centrifugal distribution (face/extremities > trunk)\", \"Palms and soles involved\", \"All lesions at same stage of development (synchronous)\", \"Deep, rounded, firm lesions\", \"Severe prodrome (3-4 days) before rash\", \"Absence of lymphadenopathy (vs mpox)\"]}','{\"required_all\": [\"fever\"], \"required_any\": [\"rash_vesicular_pustular\"], \"soft_require_any\": [\"rash_face_first\", \"rash_palms_soles\", \"back_pain\"], \"hard_fail_if_absent\": []}','{\"fever\": 12, \"vomiting\": 4, \"back_pain\": 12, \"high_fever\": 14, \"abdominal_pain\": 4, \"severe_fatigue\": 8, \"mucosal_lesions\": 8, \"rash_face_first\": 12, \"very_high_fever\": 16, \"rash_palms_soles\": 12, \"rash_vesicular_pustular\": 24}','{\"close_contact_case\": 14, \"laboratory_exposure\": 14, \"travel_from_outbreak_area\": 8}',NULL,'{\"rash_vesicular_pustular\": -24}','[{\"id\": \"WHO_IHR_2005_ANNEX2\", \"url\": \"https://apps.who.int/gb/bd/pdf_files/IHR_2014-2022-2024-en.pdf\", \"title\": \"International Health Regulations (2005) — Annex 2\"}, {\"id\": \"WHO_AFRO_IDSR_2021\", \"url\": \"https://www.afro.who.int/sites/default/files/2021-09/Final_IDSR%20Technical%20Guidelines_Final%20Version%20signed%20by%20%20Hon.%20DG%20and%20Hon.%20Minister.pdf\", \"title\": \"WHO AFRO IDSR Technical Guidelines 2021 (3rd Ed.)\"}, {\"id\": \"WHO_DISEASE_FACT_SHEETS\", \"url\": \"https://www.who.int/news-room/fact-sheets\", \"title\": \"WHO Disease Fact Sheets 2024\"}, {\"id\": \"CDC_YELLOW_BOOK_2024\", \"url\": \"https://wwwnc.cdc.gov/travel/yellowbook/2024\", \"title\": \"CDC Yellow Book 2024 — Travelers\' Health\"}, {\"id\": \"MANDELL_9TH_ED\", \"notes\": \"LR-calibrated symptom weights\", \"title\": \"Mandell, Douglas, and Bennett\'s Principles of Infectious Diseases, 9th Edition\"}, {\"id\": \"GEOSENTINEL_TROPNET\", \"notes\": \"Prevalence calibration in symptomatic returning travellers\", \"title\": \"GeoSentinel / TropNetEurop Travel Medicine Database\"}]','{\"id\": \"smallpox\", \"name\": \"Smallpox\", \"gates\": {\"required_all\": [\"fever\"], \"required_any\": [\"rash_vesicular_pustular\"], \"soft_require_any\": [\"rash_face_first\", \"rash_palms_soles\", \"back_pain\"], \"hard_fail_if_absent\": []}, \"severity\": 5, \"hallmarks\": [\"fever\", \"rash_vesicular_pustular\", \"rash_face_first\"], \"syndromes\": [\"vesiculopustular_rash\", \"high_consequence_rash\"], \"who_basis\": \"IHR 2005 — always notifiable. WHO smallpox eradication surveillance guidance.\", \"who_category\": \"IHR_TIER1_ALWAYS_NOTIFIABLE\", \"priority_tier\": \"tier_1_ihr_critical\", \"outbreak_bonus\": 20, \"incubation_days\": {\"max\": 17, \"min\": 7, \"typical\": \"10-14\"}, \"onset_modifiers\": {\"days_since_onset_7_to_17\": 3}, \"symptom_weights\": {\"fever\": 12, \"vomiting\": 4, \"back_pain\": 12, \"high_fever\": 14, \"abdominal_pain\": 4, \"severe_fatigue\": 8, \"mucosal_lesions\": 8, \"rash_face_first\": 12, \"very_high_fever\": 16, \"rash_palms_soles\": 12, \"rash_vesicular_pustular\": 24}, \"exposure_weights\": {\"close_contact_case\": 14, \"laboratory_exposure\": 14, \"travel_from_outbreak_area\": 8}, \"negative_weights\": {\"coryza\": -6, \"conjunctivitis\": -6, \"watery_diarrhea\": -8, \"loss_of_taste_smell\": -8, \"swollen_lymph_nodes\": -10}, \"endemic_countries\": [], \"immediate_actions\": [\"MAXIMUM ISOLATION\", \"IMMEDIATE IHR WHO NOTIFICATION\", \"BIOTERRORISM PROTOCOL\", \"Contact tracing of all contacts since rash onset\"], \"recommended_tests\": [\"Immediate WHO/national public health emergency pathway — BSL-4 only\", \"DO NOT attempt routine lab — activate bioterrorism protocol\"], \"key_distinguishers\": [\"Centrifugal distribution (face/extremities > trunk)\", \"Palms and soles involved\", \"All lesions at same stage of development (synchronous)\", \"Deep, rounded, firm lesions\", \"Severe prodrome (3-4 days) before rash\", \"Absence of lymphadenopathy (vs mpox)\"], \"who_case_definition\": {\"source\": \"WHO Smallpox Preparedness; IHR Annex 2.\", \"probable\": \"A suspected case with no alternative diagnosis and negative monkeypox result.\", \"confirmed\": \"Variola virus detected by PCR or electron microscopy in specialized BSL-4 laboratory.\", \"suspected\": \"ANY PERSON with febrile prodrome (2-4 days before rash) followed by centrifugal vesicular/pustular rash appearing simultaneously on face, arms, and trunk — with all lesions at the same stage of development.\", \"poe_action\": \"IMMEDIATE FULL ISOLATION. DO NOT RELEASE TRAVELLER. Notify WHO NFP and national emergency contacts IMMEDIATELY.\", \"ihr_category\": \"IHR Tier 1 — ALWAYS NOTIFIABLE. BIOTERRORISM PROTOCOL.\"}, \"vaccination_modifiers\": [], \"case_fatality_rate_pct\": 30, \"absent_hallmark_penalties\": {\"rash_vesicular_pustular\": -24}, \"alert_level_if_top_ranked\": \"critical\"}',1,NULL,NULL,'2026-05-17 15:08:23','2026-05-17 16:09:12'),(2,'sars','Severe Acute Respiratory Syndrome (SARS)',1,'severe_respiratory',2,10,'{\"cfr_pct\": 10, \"severity\": 5, \"hallmarks\": [\"fever\", \"cough\", \"shortness_of_breath\"], \"syndromes\": [\"severe_respiratory\"], \"who_basis\": \"IHR 2005 — always notifiable. Retained in scoring engine per IHR legal obligation.\",