--
-- Table structure for table `ref_endemic_countries`
--

DROP TABLE IF EXISTS `ref_endemic_countries`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ref_endemic_countries` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `disease_code` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL,
  `country_code` varchar(3) COLLATE utf8mb4_unicode_ci NOT NULL,
  `country_name` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `endemicity_level` enum('ENDEMIC','OUTBREAK_ACTIVE','OUTBREAK_RECENT','SPORADIC','IMPORTED_ONLY') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ENDEMIC',
  `since_year` smallint unsigned DEFAULT NULL,
  `source` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `last_verified_at` date DEFAULT NULL,
  `payload` json DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_by_user_id` bigint unsigned DEFAULT NULL,
  `updated_by_user_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `ref_endemic_countries_pair_unique` (`disease_code`,`country_code`),
  KEY `ref_endemic_countries_disease_code_index` (`disease_code`),
  KEY `ref_endemic_countries_country_code_index` (`country_code`),
  KEY `ref_endemic_countries_endemicity_level_index` (`endemicity_level`),
  KEY `ref_endemic_countries_is_active_index` (`is_active`)
) ENGINE=InnoDB AUTO_INCREMENT=3310 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

