INSERT INTO `ref_engine_config` VALUES (1,'diseases.metadata','window.DISEASES.metadata from src/Diseases.js','{\"purpose\": \"Weighted, audit-friendly, WHO/IHR-aligned disease scoring engine for POE syndromic triage.\", \"version\": \"3.0.0\", \"scope_note\": \"Covers all IHR Annex 2 always-notifiable diseases, all WHO AFRO IDSR Priority 1 diseases, and the most clinically relevant travel-medicine differentials for East/Central Africa POE screening.\", \"created_utc\": \"2026-04-17T00:00:00Z\", \"design_note\": \"Explainable rules engine, not a statistically calibrated diagnostic model. All weights are LR-calibrated from Mandell 9th Ed. and WHO AFRO IDSR 2021. Syndrome bonuses and outbreak bonuses applied by Diseases_intelligence.js patch.\", \"dataset_name\": \"who_poe_unified_matcher_v3\", \"disease_count\": 42, \"schema_version\": \"3.0.0\"}','3.0.0','metadata',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(2,'diseases.sources','window.DISEASES.sources from src/Diseases.js','[{\"id\": \"WHO_IHR_2005_ANNEX2\", \"url\": \"https://apps.who.int/gb/bd/pdf_files/IHR_2014-2022-2024-en.pdf\", \"title\": \"International Health Regulations (2005) — Annex 2\"}, {\"id\": \"WHO_AFRO_IDSR_2021\", \"url\": \"https://www.afro.who.int/sites/default/files/2021-09/Final_IDSR%20Technical%20Guidelines_Final%20Version%20signed%20by%20%20Hon.%20DG%20and%20Hon.%20Minister.pdf\", \"title\": \"WHO AFRO IDSR Technical Guidelines 2021 (3rd Ed.)\"}, {\"id\": \"WHO_DISEASE_FACT_SHEETS\", \"url\": \"https://www.who.int/news-room/fact-sheets\", \"title\": \"WHO Disease Fact Sheets 2024\"}, {\"id\": \"CDC_YELLOW_BOOK_2024\", \"url\": \"https://wwwnc.cdc.gov/travel/yellowbook/2024\", \"title\": \"CDC Yellow Book 2024 — Travelers\' Health\"}, {\"id\": \"MANDELL_9TH_ED\", \"notes\": \"LR-calibrated symptom weights\", \"title\": \"Mandell, Douglas, and Bennett\'s Principles of Infectious Diseases, 9th Edition\"}, {\"id\": \"GEOSENTINEL_TROPNET\", \"notes\": \"Prevalence calibration in symptomatic returning travellers\", \"title\": \"GeoSentinel / TropNetEurop Travel Medicine Database\"}]','3.0.0','reference',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(3,'diseases.engine','window.DISEASES.engine from src/Diseases.js','{\"name\": \"WHO-POE Unified Explainable Matcher v3\", \"formula\": {\"description\": \"final_score = gate_score + symptom_score + exposure_score + syndrome_bonus + outbreak_bonus + vaccination_modifier + onset_modifier + absent_hallmark_penalty + contradiction_penalty + override_boost\", \"max_score_cap\": 100, \"gate_pass_bonus\": 12, \"min_score_floor\": 0, \"syndrome_bonus_match\": 8, \"gate_hard_fail_penalty\": -60, \"gate_soft_fail_penalty\": -18, \"outbreak_bonus_default\": 15, \"contradiction_penalty_default\": -6, \"absent_mandatory_hallmark_penalty\": -12, \"absent_penalise_only_if_sensitivity_gte\": 0.8, \"strong_documented_vaccination_reduction\": -14, \"documented_valid_vaccination_reduction_default\": -8}, \"normalization\": {\"confidence_bands\": [{\"band\": \"very_high\", \"color\": \"#DC3545\", \"min_score\": 70, \"poe_action\": \"MANDATORY_ISOLATION_AND_IHR_NOTIFICATION\"}, {\"band\": \"high\", \"color\": \"#E85D04\", \"min_score\": 55, \"poe_action\": \"SECONDARY_REFERRAL_URGENT\"}, {\"band\": \"moderate\", \"color\": \"#FFC107\", \"min_score\": 40, \"poe_action\": \"SECONDARY_REFERRAL\"}, {\"band\": \"low\", \"color\": \"#17A2B8\", \"min_score\": 25, \"poe_action\": \"DOCUMENT_AND_MONITOR\"}, {\"band\": \"minimal\", \"color\": \"#6C757D\", \"min_score\": 0, \"poe_action\": \"STANDARD_PRECAUTIONS\"}], \"minimum_data_rule\": \"If fewer than 2 symptoms and no exposure selected, confidence = minimal regardless of raw score.\", \"rank_to_probability_like_percent\": \"prob_like = round(100 * disease_score / sum(top_5_scores)) — displayed over top candidates only when total > 0\"}, \"output_sorting\": [\"Sort descending by final_score\", \"Break ties by higher priority tier (tier_1 > tier_2 > tier_3)\", \"Then by greater number of matched hallmark symptoms\", \"Then by greater number of matched exposure signals\", \"Always pin tier_1 and tier_2_ihr_annex2 above lower tiers when scores within 8 points\"], \"triage_overrides\": [{\"effect\": {\"boost_diseases\": {\"cchf\": 18, \"hantavirus\": 10, \"lassa_fever\": 12, \"yellow_fever\": 8, \"rift_valley_fever\": 8, \"ebola_virus_disease\": 18, \"marburg_virus_disease\": 18}, \"force_alert_level\": \"critical\", \"mandatory_actions\": [\"FULL_PPE\", \"IMMEDIATE_ISOLATION\", \"NOTIFY_IHR_FOCAL_POINT\"]}, \"and_any\": [\"contact_body_fluids\", \"contact_dead_body\", \"healthcare_exposure\", \"rodent_exposure\", \"travel_from_outbreak_area\", \"funeral_or_burial_exposure\"], \"rule_id\": \"override_vhf_red_flag\", \"priority\": 1, \"when_all\": [\"fever\", \"bleeding\"], \"description\": \"Fever + any haemorrhage + any relevant exposure = VHF protocol — highest POE emergency\"}, {\"effect\": {\"boost_diseases\": {\"cchf\": 14, \"yellow_fever\": 8, \"dengue_severe\": 12, \"ebola_virus_disease\": 10, \"marburg_virus_disease\": 10}, \"force_alert_level\": \"critical\"}, \"and_any\": [\"bleeding\", \"bleeding_gums_or_nose\", \"bloody_sputum\", \"petechial_or_purpuric_rash\"], \"rule_id\": \"override_any_haemorrhage_fever_no_exposure\", \"priority\": 2, \"when_all\": [\"fever\"], \"description\": \"Fever + any spontaneous haemorrhage even without confirmed exposure = VHF screening pathway\"}, {\"effect\": {\"boost_diseases\": {\"polio\": 35, \"west_nile_fever\": 8, \"japanese_encephalitis\": 8}, \"force_alert_level\": \"critical\", \"mandatory_actions\": [\"NOTIFY_WHO_AFP_SURVEILLANCE\", \"STOOL_SPECIMENS_X2\"]}, \"rule_id\": \"override_acute_flaccid_paralysis\", \"priority\": 3, \"when_any\": [\"paralysis_acute_flaccid\"], \"description\": \"ANY acute flaccid paralysis = mandatory AFP/polio escalation regardless of all other findings\"}, {\"effect\": {\"boost_diseases\": {\"meningococcal_meningitis\": 20}, \"force_alert_level\": \"critical\", \"mandatory_actions\": [\"EMERGENCY_MEDICAL_REFERRAL\", \"IV_ANTIBIOTICS_WITHOUT_DELAY\"]}, \"rule_id\": \"override_meningitis_triad\", \"priority\": 4, \"when_all\": [\"fever\", \"stiff_neck\"], \"description\": \"Fever + stiff neck = bacterial meningitis/septicaemia — minutes matter\"}, {\"effect\": {\"boost_diseases\": {\"mpox\": 16, \"smallpox\": 16}, \"force_alert_level\": \"high\", \"penalize_diseases\": {\"measles\": 10, \"rubella\": 10}}, \"rule_id\": \"override_vesiculopustular_rash\", \"priority\": 5, \"when_any\": [\"rash_vesicular_pustular\", \"mucosal_lesions\"], \"description\": \"Vesicular/pustular rash = mpox/smallpox pathway\"}, {\"effect\": {\"boost_diseases\": {\"smallpox\": 30}, \"force_alert_level\": \"critical\", \"mandatory_actions\": [\"MAXIMUM_ISOLATION\", \"IMMEDIATE_IHR_WHO_NOTIFICATION\", \"BIOTERRORISM_PROTOCOL\"]}, \"rule_id\": \"override_smallpox_pustular_centrifugal\", \"priority\": 6, \"when_all\": [\"fever\", \"rash_vesicular_pustular\", \"rash_face_first\"], \"description\": \"Pustular centrifugal rash (face/palms/soles > trunk) + fever = GLOBAL BIOLOGICAL EMERGENCY until excluded\"}, {\"effect\": {\"boost_diseases\": {\"cholera\": 18, \"awd_non_cholera\": 8}, \"force_alert_level\": \"high\", \"mandatory_actions\": [\"AGGRESSIVE_REHYDRATION\", \"ISOLATE_ENTERIC_PRECAUTIONS\"]}, \"rule_id\": \"override_watery_diarrhea_dehydration\", \"priority\": 7, \"when_any\": [\"watery_diarrhea\", \"rice_water_diarrhea\", \"severe_dehydration\"], \"description\": \"Profuse watery diarrhoea OR severe dehydration = cholera protocol immediately\"}, {\"effect\": {\"boost_diseases\": {\"rabies\": 50}, \"force_alert_level\": \"critical\", \"mandatory_actions\": [\"EMERGENCY_REFERRAL\", \"ASSESS_BITE_HISTORY\", \"PEP_EVALUATION\"]}, \"rule_id\": \"override_rabies_pathognomonic\", \"priority\": 8, \"when_any\": [\"hydrophobia\", \"aerophobia\"], \"description\": \"Hydrophobia OR aerophobia = rabies until excluded — virtually 100% fatal once symptomatic\"}, {\"effect\": {\"boost_diseases\": {\"tularemia\": 15, \"anthrax_cutaneous\": 30, \"rickettsia_scrub_typhus\": 18}, \"force_alert_level\": \"high\", \"mandatory_actions\": [\"SECONDARY_REFERRAL\", \"BIOTERRORISM_ASSESSMENT_IF_CLUSTER\"]}, \"rule_id\": \"override_skin_eschar\", \"priority\": 9, \"when_any\": [\"skin_eschar\"], \"description\": \"Painless black necrotic skin ulcer = anthrax or rickettsia — bioterrorism consideration if cluster\"}, {\"effect\": {\"force_alert_level\": \"critical\", \"mandatory_actions\": [\"NOTIFY_IHR_NATIONAL_FOCAL_POINT\", \"DOCUMENT_IN_SURVEILLANCE_SYSTEM\"]}, \"rule_id\": \"override_ihr_annex2_any_match\", \"priority\": 10, \"description\": \"Any IHR Tier 1 disease in top 3 results = mandatory public health notification\", \"applies_to_tiers\": [\"tier_1_ihr_critical\", \"tier_2_ihr_annex2_epidemic_prone\"]}], \"ranking_principles\": [\"Gate diseases by their strongest hallmark or syndrome requirement — no gate pass = hard exclusion.\", \"Reward signature symptoms more than generic symptoms using LR-calibrated weights.\", \"Boost scores using exposure and outbreak epidemiological context.\", \"Penalise contradictions when clearly conflicting symptoms are confirmed absent.\", \"Promote high-consequence IHR diseases when red-flag patterns exist, even when symptom overlap is high.\", \"Fire triage overrides as hard rules independent of and before scoring — safety first.\", \"Apply absent-symptom penalties only for mandatory hallmark symptoms with sensitivity >= 0.80.\"]}','3.0.0','engine',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(4,'diseases.input_schema','window.DISEASES.input_schema from src/Diseases.js','{\"clinical_context\": {\"pregnant\": \"optional boolean\", \"age_group\": \"optional child|adolescent|adult|older_adult\", \"temperature_c\": \"optional number\", \"days_since_onset\": \"optional integer\"}, \"outbreak_context\": \"optional string[] — disease ids currently active in source, destination, or transit corridor\", \"selected_symptoms\": \"string[] — symptom ids from symptom_catalog\", \"selected_exposures\": \"optional string[] — exposure ids from exposure_catalog\", \"vaccination_history\": {\"polio\": \"unknown|documented_valid|not_vaccinated\", \"rabies\": \"unknown|documented_valid|not_vaccinated\", \"measles\": \"unknown|documented_valid|not_vaccinated\", \"rubella\": \"unknown|documented_valid|not_vaccinated\", \"covid_19\": \"unknown|documented_valid|not_vaccinated\", \"hepatitis_a\": \"unknown|documented_valid|not_vaccinated\", \"yellow_fever\": \"unknown|documented_valid|documented_invalid_or_expired|not_vaccinated\", \"japanese_encephalitis\": \"unknown|documented_valid|not_vaccinated\"}, \"explicit_absent_symptoms\": \"optional string[] — symptom ids CONFIRMED absent (triggers absent-hallmark penalties)\"}','3.0.0','reference',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(5,'diseases.symptom_catalog','window.DISEASES.symptom_catalog from src/Diseases.js','[{\"id\": \"fever\", \"label\": \"Fever (≥38.0°C)\", \"who_priority\": true}, {\"id\": \"high_fever\", \"label\": \"High fever (≥39.0°C)\", \"who_priority\": true}, {\"id\": \"very_high_fever\", \"label\": \"Very high fever (≥40.0°C)\", \"who_priority\": true}, {\"id\": \"low_grade_fever\", \"label\": \"Low-grade fever (37.5–38.0°C)\", \"who_priority\": false}, {\"id\": \"sudden_onset_fever\", \"label\": \"Sudden-onset fever — patient recalls exact hour\", \"who_priority\": false}, {\"id\": \"gradual_onset_fever\", \"label\": \"Gradual-onset fever — worsening over days\", \"who_priority\": false}, {\"id\": \"undulant_fever\", \"label\": \"Undulant fever — rises and falls cyclically\", \"who_priority\": false}, {\"id\": \"paradoxical_bradycardia\", \"label\": \"Paradoxical bradycardia (slow pulse despite fever)\", \"who_priority\": false}, {\"id\": \"chills\", \"label\": \"Chills / rigors\", \"who_priority\": false}, {\"id\": \"night_sweats\", \"label\": \"Night sweats\", \"who_priority\": false}, {\"id\": \"cough\", \"label\": \"Cough\", \"who_priority\": true}, {\"id\": \"dry_cough\", \"label\": \"Dry cough\", \"who_priority\": false}, {\"id\": \"sore_throat\", \"label\": \"Sore throat\", \"who_priority\": false}, {\"id\": \"coryza\", \"label\": \"Runny / blocked nose\", \"who_priority\": false}, {\"id\": \"shortness_of_breath\", \"label\": \"Shortness of breath\", \"who_priority\": true}, {\"id\": \"difficulty_breathing\", \"label\": \"Difficulty breathing / respiratory distress\", \"who_priority\": true}, {\"id\": \"rapid_breathing\", \"label\": \"Rapid breathing / tachypnoea\", \"who_priority\": true}, {\"id\": \"chest_pain\", \"label\": \"Chest pain\", \"who_priority\": false}, {\"id\": \"retrosternal_pain\", \"label\": \"Retrosternal / behind-sternum pain\", \"who_priority\": false}, {\"id\": \"bloody_sputum\", \"label\": \"Blood-stained sputum / haemoptysis\", \"who_priority\": true}, {\"id\": \"nausea\", \"label\": \"Nausea\", \"who_priority\": false}, {\"id\": \"vomiting\", \"label\": \"Vomiting\", \"who_priority\": false}, {\"id\": \"persistent_vomiting\", \"label\": \"Persistent or severe vomiting\", \"who_priority\": true}, {\"id\": \"hiccups\", \"label\": \"Intractable hiccups\", \"who_priority\": false}, {\"id\": \"diarrhea\", \"label\": \"Diarrhoea (general)\", \"who_priority\": false}, {\"id\": \"watery_diarrhea\", \"label\": \"Acute watery diarrhoea\", \"who_priority\": true}, {\"id\": \"rice_water_diarrhea\", \"label\": \"Rice-water / profuse watery stool\", \"who_priority\": true}, {\"id\": \"bloody_diarrhea\", \"label\": \"Bloody diarrhoea / dysentery\", \"who_priority\": true}, {\"id\": \"severe_dehydration\", \"label\": \"Severe dehydration\", \"who_priority\": true}, {\"id\": \"abdominal_pain\", \"label\": \"Abdominal pain\", \"who_priority\": false}, {\"id\": \"abdominal_tenderness\", \"label\": \"Abdominal tenderness / guarding\", \"who_priority\": false}, {\"id\": \"jaundice\", \"label\": \"Jaundice / yellow ey