DROP TABLE IF EXISTS `ref_exposures`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ref_exposures` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `exposure_code` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL,
  `display_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` varchar(60) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `prompt_text` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `response_type` enum('YES_NO','YES_NO_UNKNOWN','MULTI_SELECT','TEXT','NUMERIC') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'YES_NO',
  `is_high_risk` tinyint(1) NOT NULL DEFAULT '0',
  `triggers_diseases` json DEFAULT NULL,
  `payload` json DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_by_user_id` bigint unsigned DEFAULT NULL,
  `updated_by_user_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `ref_exposures_exposure_code_unique` (`exposure_code`),
  KEY `ref_exposures_category_index` (`category`),
  KEY `ref_exposures_is_high_risk_index` (`is_high_risk`),
  KEY `ref_exposures_is_active_index` (`is_active`)
) ENGINE=InnoDB AUTO_INCREMENT=60 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

