INSERT INTO `ref_exposures` VALUES (1,'TRAVEL_OUTBREAK_AREA','Travel to area with active outbreak or known public health event','travel_geographic',NULL,'YES_NO',0,NULL,'{\"code\": \"TRAVEL_OUTBREAK_AREA\", \"label\": \"Travel to area with active outbreak or known public health event\", \"category\": \"travel_geographic\", \"risk_level\": \"HIGH\", \"description\": \"Visited a country, city, or specific geographic zone with an active WHO-notified outbreak, disease event, or elevated public health risk within the past 21 days.\", \"who_ihr_ref\": \"IHR 2005 Art. 23(1)(a); AFRO IDSR 2021 §4.2\", \"engine_codes\": [\"travel_from_outbreak_area\", \"residence_in_outbreak_area\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"cholera\", \"ebola_virus_disease\", \"yellow_fever\", \"mpox\", \"meningococcal_meningitis\", \"dengue\", \"malaria_severe\"], \"screening_questions\": [\"Which country/region specifically?\", \"Was there an active WHO Disease Outbreak News for that area?\", \"Did you have contact with ill people in that area?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(2,'RESIDENCE_OUTBREAK_AREA','Resident of area with ongoing outbreak','travel_geographic',NULL,'YES_NO',0,NULL,'{\"code\": \"RESIDENCE_OUTBREAK_AREA\", \"label\": \"Resident of area with ongoing outbreak\", \"category\": \"travel_geographic\", \"risk_level\": \"HIGH\", \"description\": \"The traveller currently resides or spent >14 days in a geographic zone with documented endemic transmission of a notifiable disease.\", \"who_ihr_ref\": \"IHR 2005 Art. 23(1)(a)\", \"engine_codes\": [\"residence_in_outbreak_area\", \"travel_from_outbreak_area\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"cholera\", \"malaria_uncomplicated\", \"typhoid_fever\", \"dengue\", \"lassa_fever\"], \"screening_questions\": [\"Exact location of residence?\", \"Duration of stay?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(3,'CONTACT_SICK_PERSON','Close contact with a symptomatic individual','person_contact',NULL,'YES_NO',0,NULL,'{\"code\": \"CONTACT_SICK_PERSON\", \"label\": \"Close contact with a symptomatic individual\", \"category\": \"person_contact\", \"risk_level\": \"MODERATE\", \"description\": \"Face-to-face contact within 1 metre, or direct physical contact, with a person who was ill with symptoms compatible with infectious disease within the past 21 days.\", \"who_ihr_ref\": \"IHR 2005 Art. 23(1)(a); AFRO IDSR 2021 §5.1\", \"engine_codes\": [\"close_contact_case\", \"contact_body_fluids\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"influenza_new_subtype_zoonotic\", \"measles\", \"meningococcal_meningitis\", \"mers\", \"sars\"], \"screening_questions\": [\"What symptoms did the sick person have?\", \"Were you within 1 metre without protection?\", \"Did you share a room, vehicle, or food?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(4,'CONTACT_CONFIRMED_CASE','Direct contact with a confirmed or suspected disease case','person_contact',NULL,'YES_NO',0,NULL,'{\"code\": \"CONTACT_CONFIRMED_CASE\", \"label\": \"Direct contact with a confirmed or suspected disease case\", \"category\": \"person_contact\", \"risk_level\": \"HIGH\", \"description\": \"Known or suspected contact with a person officially classified as a confirmed or probable case of a notifiable infectious disease by a health authority.\", \"who_ihr_ref\": \"IHR 2005 Art. 23(1)(a); WHO Contact Tracing Guidelines 2021\", \"engine_codes\": [\"close_contact_case\", \"contact_body_fluids\", \"affected_healthcare_facility_exposure\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"ebola_virus_disease\", \"marburg_virus_disease\", \"lassa_fever\", \"mpox\", \"cholera\", \"meningococcal_meningitis\"], \"screening_questions\": [\"What disease was the confirmed case diagnosed with?\", \"What was the nature of contact (physical, respiratory, shared space)?\", \"Were you wearing PPE during the contact?\", \"Date of last contact?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(5,'CONTACT_RASH_CASE','Contact with person having unexplained rash or skin lesions','person_contact',NULL,'YES_NO',0,NULL,'{\"code\": \"CONTACT_RASH_CASE\", \"label\": \"Contact with person having unexplained rash or skin lesions\", \"category\": \"person_contact\", \"risk_level\": \"HIGH\", \"description\": \"Direct skin or mucous membrane contact with a person exhibiting unexplained vesicular, pustular, or ulcerative skin lesions (relevant for mpox, varicella, smallpox differential).\", \"who_ihr_ref\": \"WHO Mpox Guidance 2024; IHR Annex 2\", \"engine_codes\": [\"contact_with_rash_case\", \"close_contact_case\", \"sexual_contact\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"mpox\", \"smallpox\", \"measles\", \"rubella\", \"chickenpox\"], \"screening_questions\": [\"Where were the lesions located (face, hands, genitals, trunk)?\", \"Did you have sexual contact with this person?\", \"Was the person diagnosed with anything?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(6,'SEXUAL_CONTACT','Sexual contact with a new or unknown partner (particularly in endemic area)','person_contact',NULL,'YES_NO',0,NULL,'{\"code\": \"SEXUAL_CONTACT\", \"label\": \"Sexual contact with a new or unknown partner (particularly in endemic area)\", \"category\": \"person_contact\", \"risk_level\": \"MODERATE\", \"description\": \"Recent sexual contact with one or more new or unknown partners, particularly if the contact occurred in a country with elevated STI or mpox transmission.\", \"who_ihr_ref\": \"WHO Sexual Health Guidelines 2022; Mpox Guidance 2024\", \"engine_codes\": [\"sexual_contact\", \"close_contact_case\", \"contact_with_rash_case\"], \"lookback_days\": 21, \"requires_details\": false, \"priority_diseases\": [\"mpox\", \"zika\", \"rubella\", \"hepatitis_b\"], \"screening_questions\": []}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(7,'CONTACT_BODY_FLUIDS','Exposure to blood or body fluids of a symptomatic or deceased person','body_fluid_exposure',NULL,'YES_NO',0,NULL,'{\"code\": \"CONTACT_BODY_FLUIDS\", \"label\": \"Exposure to blood or body fluids of a symptomatic or deceased person\", \"category\": \"body_fluid_exposure\", \"risk_level\": \"VERY_HIGH\", \"description\": \"Contact with blood, sweat, saliva, vomit, faeces, urine, or other body fluids of a person who was ill or deceased, without adequate personal protective equipment.\", \"who_ihr_ref\": \"IHR 2005 Art. 23; WHO Standard Precautions Guidelines 2007\", \"engine_codes\": [\"contact_body_fluids\", \"close_contact_case\", \"funeral_or_burial_exposure\", \"healthcare_exposure\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"ebola_virus_disease\", \"marburg_virus_disease\", \"lassa_fever\", \"cchf\", \"hepatitis_b\", \"hiv\"], \"screening_questions\": [\"Type of fluid (blood, vomit, faeces, urine, other)?\", \"Was the source person ill or deceased?\", \"Did the fluid contact your eyes, mouth, nose, or broken skin?\", \"Were you wearing gloves and gown?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(8,'CONTACT_DEAD_BODY','Contact with a dead body or participation in burial/funeral rites','body_fluid_exposure',NULL,'YES_NO',0,NULL,'{\"code\": \"CONTACT_DEAD_BODY\", \"label\": \"Contact with a dead body or participation in burial/funeral rites\", \"category\": \"body_fluid_exposure\", \"risk_level\": \"VERY_HIGH\", \"description\": \"Direct physical contact with a deceased person, including participation in traditional burial practices that involve touching the body, without adequate protection. Extremely high risk for VHF transmission.\", \"who_ihr_ref\": \"WHO Safe and Dignified Burial Guidelines 2021; IHR Annex 2\", \"engine_codes\": [\"contact_dead_body\", \"funeral_or_burial_exposure\", \"contact_body_fluids\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"ebola_virus_disease\", \"marburg_virus_disease\", \"lassa_fever\", \"cchf\"], \"screening_questions\": [\"Did the deceased person have symptoms of infectious illness?\", \"Did you touch the body directly (skin, fluids)?\", \"Was this a traditional burial with communal washing of the body?\", \"Did other family members become ill after the burial?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(9,'HEALTHCARE_EXPOSURE','Presence in or exposure within a healthcare facility','healthcare',NULL,'YES_NO',0,NULL,'{\"code\": \"HEALTHCARE_EXPOSURE\", \"label\": \"Presence in or exposure within a healthcare facility\", \"category\": \"healthcare\", \"risk_level\": \"MODERATE\", \"description\": \"Admitted as a patient, visited a patient, or worked as a healthcare worker in a clinic or hospital within the past 21 days, particularly in an endemic or outbreak area.\", \"who_ihr_ref\": \"IHR 2005 Art. 23; WHO Healthcare Infection Prevention 2019\", \"engine_codes\": [\"healthcare_exposure\", \"affected_healthcare_facility_exposure\", \"close_contact_case\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"mers\", \"sars\", \"influenza_new_subtype_zoonotic\", \"ebola_virus_disease\", \"cholera\", \"tuberculosis\"], \"screening_questions\": [\"Were you a patient, visitor, or healthcare worker?\", \"Were there patients with unexplained respiratory illness in the facility?\", \"Was PPE used if working clinically?\", \"Was this facility in a country with an active outbreak?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(10,'LABORATORY_EXPOSURE','Work in a laboratory handling potentially infectious biological material','healthcare',NULL,'YES_NO',0,NULL,'{\"code\": \"LABORATORY_EXPOSURE\", \"label\": \"Work in a laboratory handling potentially infectious biological material\", \"category\": \"healthcare\", \"risk_level\": \"HIGH\", \"description\": \"Occupational exposure through laboratory work with clinical specimens, cultures, or research materials that may contain pathogens, including during specimen collection.\", \"who_ihr_ref\": \"WHO Laboratory Biosafety Guidelines 2020\", \"engine_codes\": [\"laboratory_exposure\", \"contact_body_fluids\", \"healthcare_exposure\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"sars\", \"anthrax_pulmonary\", \"smallpox\", \"tularemia\", \"brucellosis\"], \"screening_questions\": [\"What type of specimens or agents were handled?\", \"Was there a needle-stick, spill, or aerosol incident?\", \"What BSL level was the facility?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(11,'ANIMAL_EXPOSURE_LIVESTOCK','Contact with livestock, farm animals, or their products','animal_zoonotic',NULL,'YES_NO',0,NULL,'{\"code\": \"ANIMAL_EXPOSURE_LIVESTOCK\", \"label\": \"Contact with livestock, farm animals, or their products\", \"category\": \"animal_zoonotic\", \"risk_level\": \"MODERATE\", \"description\": \"Direct contact with cattle, sheep, goats, camels, pigs, horses, or other farm animals, or handling of raw meat, blood, organs, hides, wool, or unpasteurized dairy from livestock.\", \"who_ihr_ref\": \"WHO One Health Framework; AFRO IDSR §8.3\", \"engine_codes\": [\"livestock_raw_dairy_abattoir\", \"animal_bite_or_wildlife_contact\", \"flood_livestock_exposure\", \"camel_exposure_or_mideast_healthcare\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"brucellosis\", \"rift_valley_fever\", \"cchf\", \"anthrax_cutaneous\", \"mers\", \"leptospirosis\"], \"screening_questions\": [\"What type of animal (camel, cattle, goat, pig, other)?\", \"Did you consume raw or undercooked meat, blood, or unpasteurized milk?\", \"Were any animals ill or dying in the area?\", \"Was there an animal die-off (epizootic) in the area?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(12,'ANIMAL_EXPOSURE_WILDLIFE','Contact with wildlife, wild animals, bushmeat, or bats','animal_zoonotic',NULL,'YES_NO',0,NULL,'{\"code\": \"ANIMAL_EXPOSURE_WILDLIFE\", \"label\": \"Contact with wildlife, wild animals, bushmeat, or bats\", \"category\": \"animal_zoonotic\", \"risk_level\": \"HIGH\", \"description\": \"Hunting, handling, butchering, or consuming wild animals (bushmeat) including primates, bats, rodents, or other wildlife. Entry into caves, mines, or bat roosting sites.\", \"who_ihr_ref\": \"WHO One Health; PREDICT Programme Guidelines\", \"engine_codes\": [\"animal_bite_or_wildlife_contact\", \"bat_cave_mine_exposure\", \"rodent_exposure\", \"flea_or_rodent_exposure\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"ebola_virus_disease\", \"marburg_virus_disease\", \"nipah_virus\", \"hantavirus\", \"rabies\", \"mpox\"], \"screening_questions\": [\"What type of wildlife (bat, primate, rodent, other)?\", \"Were any animals dead or ill when found?\", \"Did you handle, skin, or eat the animal?\", \"Did you enter caves, mines, or abandoned buildings where bats roost?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(13,'ANIMAL_BITE_SCRATCH','Bite, scratch, or lick from an animal (especially dog, bat, or primate)','animal_zoonotic',NULL,'YES_NO',0,NULL,'{\"code\": \"ANIMAL_BITE_SCRATCH\", \"label\": \"Bite, scratch, or lick from an animal (especially dog, bat, or primate)\", \"category\": \"animal_zoonotic\", \"risk_level\": \"HIGH\", \"description\": \"Any animal bite or scratch that broke the skin, or lick on broken skin or mucous membranes — particularly from dogs, bats, cats, foxes, jackals, or non-human primates. Rabies risk regardless of animal appearance.\", \"who_ihr_ref\": \"WHO Rabies PEP Guidelines 2018; IHR Art. 23\", \"engine_codes\": [\"dog_bat_animal_bite\", \"animal_bite_or_wildlife_contact\", \"bat_cave_mine_exposure\"], \"critical_flag\": true, \"lookback_days\": 21, \"critical_message\": \"ANY animal bite in a rabies-endemic country requires PEP assessment — even if vaccinated. Ask for vaccination card.\", \"requires_details\": true, \"priority_diseases\": [\"rabies\", \"herpes_b_virus\", \"mpox\"], \"screening_questions\": [\"What animal bit/scratched you?\", \"Did the wound break the skin or contact a mucous membrane?\", \"Did you receive PEP (post-exposure prophylaxis) after the injury?\", \"Was the animal behaving abnormally (aggression, disorientation)?\", \"Was the animal vaccinated against rabies?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(14,'POULTRY_BIRD_EXPOSURE','Contact with live poultry, wild birds, or live bird markets','animal_zoonotic',NULL,'YES_NO',0,NULL,'{\"code\": \"POULTRY_BIRD_EXPOSURE\", \"label\": \"Contact with live poultry, wild birds, or live bird markets\", \"category\": \"animal_zoonotic\", \"risk_level\": \"HIGH\", \"description\": \"Direct contact with live chickens, ducks, geese, or other poultry, including visiting live bird markets (wet markets), poultry farms, or handling sick/dead birds — particularly in Asia or Africa.\", \"who_ihr_ref\": \"WHO Avian Influenza Human-Animal Interface 2024; IHR Annex 2 (influenza)\", \"engine_codes\": [\"poultry_or_live_bird_exposure\", \"animal_bite_or_wildlife_contact\"], \"critical_flag\": true, \"lookback_days\": 10, \"critical_message\": \"H5N1 has >60% CFR. Any poultry exposure + severe respiratory illness = IMMEDIATE IHR notification.\", \"requires_details\": true, \"priority_diseases\": [\"influenza_new_subtype_zoonotic\"], \"screening_questions\": [\"What type of birds (chickens, ducks, geese, wild birds)?\", \"Were any birds sick or dying?\", \"Did you visit a live bird market or wet market?\", \"Did you handle carcasses or feathers without PPE?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(15,'CAMEL_EXPOSURE','Close contact with dromedary camels or camel products (Middle East)','animal_zoonotic',NULL,'YES_NO',0,NULL,'{\"code\": \"CAMEL_EXPOSURE\", \"label\": \"Close contact with dromedary camels or camel products (Middle East)\", \"category\": \"animal_zoonotic\", \"risk_level\": \"HIGH\", \"description\": \"Direct contact with dromedary camels (including camel racing, herding, or veterinary work) or consumption of raw camel milk or products — particularly in the Arabian Peninsula.\", \"who_ihr_ref\": \"WHO MERS Interim Guidance 2023; IHR Annex 2\", \"engine_codes\": [\"camel_exposure_or_mideast_healthcare\", \"livestock_raw_dairy_abattoir\", \"animal_bite_or_wildlife_contact\"], \"lookback_days\": 14, \"requires_details\": true, \"priority_diseases\": [\"mers\"], \"screening_questions\": [\"Did you have direct nose/mouth contact with camels?\", \"Did you consume raw camel milk or urine?\", \"Which country were the camels in?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(16,'RODENT_EXPOSURE','Contact with rodents, rodent droppings, or contaminated surfaces','animal_zoonotic',NULL,'YES_NO',0,NULL,'{\"code\": \"RODENT_EXPOSURE\", \"label\": \"Contact with rodents, rodent droppings, or contaminated surfaces\", \"category\": \"animal_zoonotic\", \"risk_level\": \"MODERATE\", \"description\": \"Exposure to rats, mice, or other rodents (including dead animals), or surfaces/food contaminated with rodent urine or droppings — especially in agricultural settings, storage areas, or field work.\", \"who_ihr_ref\": \"WHO Hantavirus Fact Sheet 2022; AFRO IDSR §8.4\", \"engine_codes\": [\"rodent_exposure\", \"flea_or_rodent_exposure\", \"flood_livestock_exposure\"], \"lookback_days\": 14, \"requires_details\": true, \"priority_diseases\": [\"hantavirus\", \"leptospirosis\", \"lassa_fever\", \"plague\", \"rickettsia_scrub_typhus\"], \"screening_questions\": [\"Did you handle live or dead rodents?\", \"Did you clean or enter a building with visible rodent droppings?\", \"Did this occur indoors in an agricultural or rural setting?\", \"Were you in a flood-affected area (leptospirosis risk)?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(17,'UNSAFE_FOOD_WATER','Consumption of potentially contaminated food or water','food_water',NULL,'YES_NO',0,NULL,'{\"code\": \"UNSAFE_FOOD_WATER\", \"label\": \"Consumption of potentially contaminated food or water\", \"category\": \"food_water\", \"risk_level\": \"MODERATE\", \"description\": \"Drinking untreated tap water, surface water, or well water; consuming raw/undercooked food, street food, or food of unknown origin — particularly in low-WASH settings.\", \"who_ihr_ref\": \"WHO WASH Guidelines 2017; AFRO IDSR §6.1\", \"engine_codes\": [\"unsafe_water\", \"contaminated_food_or_water\"], \"lookback_days\": 14, \"requires_details\": false, \"priority_diseases\": [\"cholera\", \"typhoid_fever\", \"hepatitis_a\", \"hepatitis_e\", \"shigellosis_dysentery\", \"awd_non_cholera\"], \"screening_questions\": [\"Did you drink tap water, well water, or river water directly?\", \"Did you eat from street vendors or at communal meals?\", \"Were others in your group also ill after eating the same food?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(18,'RAW_MEAT_BLOOD','Consumption of raw or undercooked meat, blood, or organ meat','food_water',NULL,'YES_NO',0,NULL,'{\"code\": \"RAW_MEAT_BLOOD\", \"label\": \"Consumption of raw or undercooked meat, blood, or organ meat\", \"category\": \"food_water\", \"risk_level\": \"HIGH\", \"description\": \"Eating raw, undercooked, or inadequately smoked meat — especially bushmeat, pork, goat blood, or organ meat — in endemic regions.\", \"who_ihr_ref\": \"WHO Food Safety Guidelines; AFRO IDSR §8.3\", \"engine_codes\": [\"livestock_raw_dairy_abattoir\", \"contaminated_food_or_water\", \"animal_bite_or_wildlife_contact\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"brucellosis\", \"anthrax_cutaneous\", \"rift_valley_fever\", \"cchf\", \"hepatitis_e\"], \"screening_questions\": [\"What type of meat (bushmeat, pork, beef, goat, other)?\", \"Was it raw or minimally cooked?\", \"Did you slaughter or butcher the animal yourself?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(19,'DATE_PALM_SAP','Consumption of raw date palm sap or toddy','food_water',NULL,'YES_NO',0,NULL,'{\"code\": \"DATE_PALM_SAP\", \"label\": \"Consumption of raw date palm sap or toddy\", \"category\": \"food_water\", \"risk_level\": \"HIGH\", \"description\": \"Drinking raw or unboiled date palm sap (Nipah risk) or fermented palm wine — particularly in Bangladesh, India, or other South/Southeast Asian countries where fruit bats contaminate sap collection.\", \"who_ihr_ref\": \"WHO Nipah Fact Sheet 2022; Bangladesh IEDCR Guidelines\", \"engine_codes\": [\"pig_farm_date_palm_sap\", \"bat_cave_mine_exposure\", \"contaminated_food_or_water\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"nipah_virus\"], \"screening_questions\": [\"In which country did you drink date palm sap?\", \"Was the sap freshly collected or fermented?\", \"Were bats seen near the sap collection pots at night?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(20,'VECTOR_MOSQUITO','Exposure to mosquito bites in tropical/endemic area (no adequate prevention)','vector',NULL,'YES_NO',0,NULL,'{\"code\": \"VECTOR_MOSQUITO\", \"label\": \"Exposure to mosquito bites in tropical/endemic area (no adequate prevention)\", \"category\": \"vector\", \"risk_level\": \"MODERATE\", \"description\": \"Unprotected exposure to mosquito bites in a region with known mosquito-borne disease transmission — no DEET/permethrin use, no bed nets, sleeping outdoors or in unscreened accommodation.\", \"who_ihr_ref\": \"IHR 2005 Art. 22 (vector control); WHO AFRO IDSR §7\", \"engine_codes\": [\"mosquito_exposure\"], \"lookback_days\": 21, \"requires_details\": false, \"priority_diseases\": [\"malaria_uncomplicated\", \"malaria_severe\", \"dengue\", \"chikungunya\", \"zika\", \"yellow_fever\", \"west_nile_fever\", \"japanese_encephalitis\"], \"screening_questions\": [\"Were you sleeping outdoors or under an unprotected bed net?\", \"Did you use DEET or other insect repellent consistently?\", \"Were you in a malaria-endemic area without prophylaxis?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(21,'VECTOR_TICK','Tick bite or presence in tick-endemic habitat (bush, forest, grassland)','vector',NULL,'YES_NO',0,NULL,'{\"code\": \"VECTOR_TICK\", \"label\": \"Tick bite or presence in tick-endemic habitat (bush, forest, grassland)\", \"category\": \"vector\", \"risk_level\": \"MODERATE\", \"description\": \"Known tick attachment or removal from skin, or time spent in vegetation/bush/grassland in areas where ticks transmit disease — particularly in sub-Saharan Africa, Central Asia, Eastern Europe, or Balkans.\", \"who_ihr_ref\": \"ECDC Tick-borne Diseases Guidance 2023; AFRO IDSR §7.4\", \"engine_codes\": [\"tick_bite_endemic\", \"flea_or_rodent_exposure\"], \"lookback_days\": 14, \"requires_details\": true, \"priority_diseases\": [\"cchf\", \"rickettsia_scrub_typhus\", \"tularemia\", \"lyme_disease\"], \"screening_questions\": [\"Did you find an attached tick on your body?\", \"In which country/region did this occur?\", \"How long was the tick attached (hours, days)?\", \"Was the tick removed properly or crushed?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(22,'VECTOR_FLEA','Flea bites or contact with flea-infested animals or environments','vector',NULL,'YES_NO',0,NULL,'{\"code\": \"VECTOR_FLEA\", \"label\": \"Flea bites or contact with flea-infested animals or environments\", \"category\": \"vector\", \"risk_level\": \"MODERATE\", \"description\": \"Bites from fleas, particularly from rodents — in endemic plague regions (Sub-Saharan Africa, Asia) or other flea-borne disease areas.\", \"who_ihr_ref\": \"WHO Plague Fact Sheet 2022; AFRO IDSR §7.5\", \"engine_codes\": [\"flea_or_rodent_exposure\", \"rodent_exposure\"], \"lookback_days\": 7, \"requires_details\": true, \"priority_diseases\": [\"pneumonic_plague\", \"bubonic_plague\", \"rickettsia_scrub_typhus\"], \"screening_questions\": [\"Did you see unusual numbers of dead rodents near your accommodation?\", \"Did you notice flea bites on your body?\", \"Were you in a known plague-endemic district?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(23,'ABATTOIR_FARM_WORK','Work in abattoir, slaughterhouse, tannery, or processing of animal products','occupational',NULL,'YES_NO',0,NULL,'{\"code\": \"ABATTOIR_FARM_WORK\", \"label\": \"Work in abattoir, slaughterhouse, tannery, or processing of animal products\", \"category\": \"occupational\", \"risk_level\": \"HIGH\", \"description\": \"Occupational exposure during slaughter, skinning, handling of hides/wool/bones from livestock — high risk for anthrax, brucellosis, Q fever, and CCHF.\", \"who_ihr_ref\": \"WHO Anthrax in Humans and Animals 2008; AFRO IDSR §8.3\", \"engine_codes\": [\"livestock_raw_dairy_abattoir\", \"contact_body_fluids\", \"tick_bite_endemic\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"anthrax_cutaneous\", \"brucellosis\", \"cchf\", \"rift_valley_fever\", \"leptospirosis\"], \"screening_questions\": [\"What type of animal products were handled?\", \"Was PPE used (gloves, mask, eye protection)?\", \"Did you notice skin lesions on animals during slaughter?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(24,'FIELD_FLOOD_AGRICULTURE','Occupational or recreational exposure to flood water, mud, or soil','occupational',NULL,'YES_NO',0,NULL,'{\"code\": \"FIELD_FLOOD_AGRICULTURE\", \"label\": \"Occupational or recreational exposure to flood water, mud, or soil\", \"category\": \"occupational\", \"risk_level\": \"MODERATE\", \"description\": \"Wading through flood water, working in rice paddies, agricultural fields, or mining — risk for leptospirosis, schistosomiasis, typhoid through skin or mucous membrane contact with contaminated water.\", \"who_ihr_ref\": \"WHO Leptospirosis Fact Sheet 2011; AFRO IDSR §6.3\", \"engine_codes\": [\"flood_livestock_exposure\", \"unsafe_water\", \"contaminated_food_or_water\"], \"lookback_days\": 14, \"requires_details\": false, \"priority_diseases\": [\"leptospirosis\", \"typhoid_fever\", \"hepatitis_e\", \"hantavirus\"], \"screening_questions\": [\"Were there dead animals in the flood water?\", \"Did you have open skin wounds while wading?\", \"Was this in a post-flood or agricultural setting?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(25,'MASS_GATHERING','Attendance at large crowd event (concert, stadium, rally, market)','community',NULL,'YES_NO',0,NULL,'{\"code\": \"MASS_GATHERING\", \"label\": \"Attendance at large crowd event (concert, stadium, rally, market)\", \"category\": \"community\", \"risk_level\": \"MODERATE\", \"description\": \"Participation in an event gathering >1,000 people in enclosed or semi-enclosed space where prolonged close contact and respiratory transmission is possible.\", \"who_ihr_ref\": \"WHO Mass Gatherings Risk Assessment Guide 2015\", \"engine_codes\": [\"crowded_closed_setting\", \"mass_gathering_hajj_umrah\", \"close_contact_case\"], \"lookback_days\": 14, \"requires_details\": true, \"priority_diseases\": [\"measles\", \"meningococcal_meningitis\", \"influenza_seasonal\", \"influenza_new_subtype_zoonotic\", \"covid_19\"], \"screening_questions\": [\"How many people attended (approximate)?\", \"Was this indoors or outdoors?\", \"Were others visibly ill at the event?\", \"Was this event in a country with known outbreak activity?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(26,'HAJJ_UMRAH_PILGRIMAGE','Participation in Hajj, Umrah, or other major religious pilgrimage','community',NULL,'YES_NO',0,NULL,'{\"code\": \"HAJJ_UMRAH_PILGRIMAGE\", \"label\": \"Participation in Hajj, Umrah, or other major religious pilgrimage\", \"category\": \"community\", \"risk_level\": \"HIGH\", \"description\": \"Attendance at Hajj (Mecca, Saudi Arabia) or Umrah, Arba\'een (Iraq), Kumbh Mela (India), or other large-scale religious pilgrimage events with millions of attendees from multiple countries.\", \"who_ihr_ref\": \"WHO Hajj Health Requirements; Saudi MoH Guidelines 2024\", \"engine_codes\": [\"mass_gathering_hajj_umrah\", \"crowded_closed_setting\", \"camel_exposure_or_mideast_healthcare\", \"close_contact_case\"], \"lookback_days\": 21, \"requires_details\": true, \"priority_diseases\": [\"mers\", \"meningococcal_meningitis\", \"influenza_seasonal\", \"influenza_new_subtype_zoonotic\"], \"screening_questions\": [\"Which pilgrimage site and year?\", \"Did you receive MenACWY vaccination before Hajj?\", \"Did you have contact with camels during the visit?\", \"Are you presenting within 14 days of returning?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(27,'SOIL_DUST_AEROSOL','Exposure to contaminated dust, soil aerosols, or airborne particles','environmental',NULL,'YES_NO',0,NULL,'{\"code\": \"SOIL_DUST_AEROSOL\", \"label\": \"Exposure to contaminated dust, soil aerosols, or airborne particles\", \"category\": \"environmental\", \"risk_level\": \"MODERATE\", \"description\": \"Inhalation of dust or aerosols in areas with anthrax contamination (tanneries, bone meal factories), or inhalation of rodent-contaminated dust during cleaning/construction.\", \"who_ihr_ref\": \"WHO Anthrax Guidelines 2008\", \"engine_codes\": [\"livestock_raw_dairy_abattoir\", \"rodent_exposure\", \"flea_or_rodent_exposure\"], \"lookback_days\": 14, \"requires_details\": true, \"priority_diseases\": [\"anthrax_pulmonary\", \"hantavirus\", \"tularemia\"], \"screening_questions\": [\"What was the location and nature of the dust exposure?\", \"Were you cleaning or disturbing old rodent nests?\", \"Were you in a tannery, wool factory, or bone processing facility?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(28,'UNVACCINATED','No or unknown vaccination status for vaccine-preventable diseases','vaccination_status',NULL,'YES_NO',0,NULL,'{\"code\": \"UNVACCINATED\", \"label\": \"No or unknown vaccination status for vaccine-preventable diseases\", \"category\": \"vaccination_status\", \"risk_level\": \"MODERATE\", \"description\": \"Traveller cannot produce valid vaccination records, or confirms NOT being vaccinated against one or more relevant vaccine-preventable diseases.\", \"who_ihr_ref\": \"IHR 2005 Annex 7 (vaccination certificates)\", \"engine_codes\": [\"unvaccinated_or_unknown_vaccination\"], \"lookback_days\": 365, \"requires_details\": true, \"priority_diseases\": [\"measles\", \"yellow_fever\", \"meningococcal_meningitis\", \"polio\", \"cholera\", \"typhoid_fever\"], \"screening_questions\": [\"Do you have a valid yellow fever vaccination certificate?\", \"When did you last receive measles, meningococcal, or typhoid vaccine?\", \"Are you travelling from a yellow fever endemic zone without a valid certificate?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13'),(29,'CONTACT_PARALYSIS_CASE','Contact with a person with acute unexplained paralysis (AFP)','neurological',NULL,'YES_NO',0,NULL,'{\"code\": \"CONTACT_PARALYSIS_CASE\", \"label\": \"Contact with a person with acute unexplained paralysis (AFP)\", \"category\": \"neurological\", \"risk_level\": \"HIGH\", \"description\": \"Living in the same household or having close contact with a child or adult with acute onset flaccid limb weakness — AFP surveillance requirement for polio exclusion.\", \"who_ihr_ref\": \"WHO GPEI AFP Surveillance Manual; IHR Annex 2 (polio)\", \"engine_codes\": [\"contact_with_paralysis_case\", \"close_contact_case\", \"unvaccinated_or_unknown_vaccination\"], \"lookback_days\": 30, \"requires_details\": true, \"priority_diseases\": [\"polio\"], \"screening_questions\": [\"Is the person with paralysis a child under 15 years?\", \"Did the paralysis start suddenly (within 1-4 days)?\", \"Are stool samples being collected from the paralysed person?\", \"In which country did this contact occur?\"]}',1,NULL,NULL,'2026-05-17 15:08:24','2026-05-17 16:09:13');
