--
-- Table structure for table `ref_poes`
--

DROP TABLE IF EXISTS `ref_poes`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ref_poes` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `external_id` varchar(60) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `country_code` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL,
  `poe_code` varchar(40) COLLATE utf8mb4_unicode_ci NOT NULL,
  `poe_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `admin_level_1` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `admin_level_1_type` varchar(60) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `province_id` bigint unsigned DEFAULT NULL,
  `district` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `district_id` bigint unsigned DEFAULT NULL,
  `poe_type` enum('airport','airstrip','port','island_entry','land_border','rail','other') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'land_border',
  `transport_mode` enum('air','water','land','rail','other') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'land',
  `regional_cluster` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_national_level` tinyint(1) NOT NULL DEFAULT '0',
  `is_major_entry` tinyint(1) NOT NULL DEFAULT '0',
  `is_recommended_osbp` tinyint(1) NOT NULL DEFAULT '0',
  `border_country` varchar(80) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `latitude` decimal(10,6) DEFAULT NULL,
  `longitude` decimal(10,6) DEFAULT NULL,
  `gazette_source` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `payload` json DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `display_order` int unsigned NOT NULL DEFAULT '0',
  `created_by_user_id` bigint unsigned DEFAULT NULL,
  `updated_by_user_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `ref_poes_country_poe_unique` (`country_code`,`poe_code`),
  KEY `ref_poes_country_code_index` (`country_code`),
  KEY `ref_poes_poe_type_index` (`poe_type`),
  KEY `ref_poes_transport_mode_index` (`transport_mode`),
  KEY `ref_poes_regional_cluster_index` (`regional_cluster`),
  KEY `ref_poes_is_active_index` (`is_active`),
  KEY `ref_poes_province_id_index` (`province_id`),
  KEY `ref_poes_district_id_index` (`district_id`),
  KEY `idx_ref_poes_deleted_at` (`deleted_at`)
) ENGINE=InnoDB AUTO_INCREMENT=40 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `ref_poes`
--

LOCK TABLES `ref_poes` WRITE;
/*!40000 ALTER TABLE `ref_poes` DISABLE KEYS */;
